/**
 * Token-bucket rate limiter.
 */

export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number; // tokens per second
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  /**
   * Try to consume one token. Returns true if allowed, false if rate-limited.
   */
  tryConsume(): boolean {
    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  /**
   * Get the current number of available tokens.
   */
  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  /**
   * Reset the limiter to full capacity.
   */
  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;

    // elapsed is in ms, refillRate is tokens per second
    const newTokens = (elapsed * this.refillRate) / 1000;

    // Cap at maxTokens so the bucket never over-fills
    this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);

    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];

export type Filter = (record: Record) => boolean;

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((f) => f(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.some((f) => f(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      const combined = andFilter(...this.filters);
      result = result.filter(combined);
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

interface FieldSpec {
  name: string;
  min: number;
  max: number;
}

const FIELDS: FieldSpec[] = [
  { name: 'minute', min: 0, max: 59 },
  { name: 'hour', min: 0, max: 23 },
  { name: 'day-of-month', min: 1, max: 31 },
  { name: 'month', min: 1, max: 12 },
  { name: 'day-of-week', min: 0, max: 6 },
];

function parseInteger(value: string, spec: FieldSpec): number {
  if (!/^\d+$/.test(value)) {
    throw new CronParseError(
      `Invalid value "${value}" in ${spec.name} field`,
      spec.name
    );
  }
  return parseInt(value, 10);
}

function checkRange(value: number, spec: FieldSpec): void {
  if (value < spec.min || value > spec.max) {
    throw new CronParseError(
      `Value ${value} out of range (${spec.min}-${spec.max}) in ${spec.name} field`,
      spec.name
    );
  }
}

function parseField(field: string, spec: FieldSpec): number[] {
  if (field.trim() === '') {
    throw new CronParseError(`Empty ${spec.name} field`, spec.name);
  }

  const results = new Set<number>();
  const parts = field.split(',');

  for (const part of parts) {
    if (part === '') {
      throw new CronParseError(
        `Empty list item in ${spec.name} field`,
        spec.name
      );
    }

    let rangePart = part;
    let step: number | undefined;

    const slashIndex = part.indexOf('/');
    if (slashIndex !== -1) {
      rangePart = part.slice(0, slashIndex);
      const stepStr = part.slice(slashIndex + 1);
      if (part.indexOf('/', slashIndex + 1) !== -1) {
        throw new CronParseError(
          `Invalid step syntax "${part}" in ${spec.name} field`,
          spec.name
        );
      }
      step = parseInteger(stepStr, spec);
      if (step <= 0) {
        throw new CronParseError(
          `Step must be positive in ${spec.name} field`,
          spec.name
        );
      }
    }

    let start: number;
    let end: number;

    if (rangePart === '*') {
      start = spec.min;
      end = spec.max;
    } else if (rangePart.includes('-')) {
      const bounds = rangePart.split('-');
      if (bounds.length !== 2) {
        throw new CronParseError(
          `Invalid range "${rangePart}" in ${spec.name} field`,
          spec.name
        );
      }
      start = parseInteger(bounds[0], spec);
      end = parseInteger(bounds[1], spec);
      checkRange(start, spec);
      checkRange(end, spec);
      if (start > end) {
        throw new CronParseError(
          `Range start ${start} greater than end ${end} in ${spec.name} field`,
          spec.name
        );
      }
    } else {
      start = parseInteger(rangePart, spec);
      checkRange(start, spec);
      if (step !== undefined) {
        end = spec.max;
      } else {
        end = start;
      }
    }

    const stepValue = step ?? 1;
    for (let value = start; value <= end; value += stepValue) {
      results.add(value);
    }
  }

  return Array.from(results).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronSchedule {
  if (typeof expression !== 'string') {
    throw new CronParseError('Expression must be a string');
  }

  const trimmed = expression.trim();
  if (trimmed === '') {
    throw new CronParseError('Expression is empty');
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new CronParseError(
      `Expected 5 fields but got ${fields.length}`
    );
  }

  const [minutes, hours, daysOfMonth, months, daysOfWeek] = fields.map(
    (field, index) => parseField(field, FIELDS[index])
  );

  return {
    minutes,
    hours,
    daysOfMonth,
    months,
    daysOfWeek,
    original: expression,
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function ok(data: unknown, status = 200): Response {
  return { status, body: { success: true, data } };
}

function err(status: number, error: string): Response {
  return { status, body: { success: false, error } };
}

function checkAuth(req: Request): Response | null {
  const token = req.headers["authorization"];
  if (!token) return err(401, "Authorization required");
  if (token !== "Bearer valid-token") return err(401, "Invalid token");
  return null;
}

function asRecord(body: unknown): Record<string, unknown> {
  return body as Record<string, unknown>;
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.length > 0;
}

function isStatus(value: unknown): value is "active" | "archived" {
  return value === "active" || value === "archived";
}

export function handleRequest(req: Request): Response {
  const authError = checkAuth(req);
  if (authError) return authError;

  switch (req.method) {
    case "GET":
      return handleGet(req);
    case "POST":
      return handlePost(req);
    case "PUT":
      return handlePut(req);
    case "DELETE":
      return handleDelete(req);
    default:
      return err(405, "Method not allowed");
  }
}

function handleGet(req: Request): Response {
  const id = req.params["id"];
  if (!id) return ok(Array.from(store.values()));
  const item = store.get(id);
  return item ? ok(item) : err(404, "Item not found");
}

function handlePost(req: Request): Response {
  if (!req.body) return err(400, "Request body is required");
  const data = asRecord(req.body);
  if (!isNonEmptyString(data["name"])) {
    return err(400, "Validation failed: name is required");
  }
  const id = data["id"] as string | undefined;
  if (id && store.has(id)) return err(409, "Item already exists");

  const now = Date.now();
  const item: Item = {
    id: id || `item-${now}`,
    name: data["name"],
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  store.set(item.id, item);
  return ok(item, 201);
}

function handlePut(req: Request): Response {
  if (!req.body) return err(400, "Request body is required");
  const id = req.params["id"];
  if (!id) return err(400, "Validation failed: id parameter is required");
  const item = store.get(id);
  if (!item) return err(404, "Item not found");

  const data = asRecord(req.body);
  const updated: Item = { ...item, updatedAt: Date.now() };
  if (isNonEmptyString(data["name"])) updated.name = data["name"];
  if (isStatus(data["status"])) updated.status = data["status"];
  store.set(id, updated);
  return ok(updated);
}

function handleDelete(req: Request): Response {
  const id = req.params["id"];
  if (!id) return err(400, "Validation failed: id parameter is required");
  const item = store.get(id);
  if (!item) return err(404, "Item not found");
  store.delete(id);
  return ok({ deleted: id });
}

import { describe, it, expect } from "vitest";
import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  it("merges flat objects", () => {
    const target = { a: 1, b: 2 };
    const source = { b: 3, c: 4 };
    const result = deepMerge(target as Record<string, unknown>, source);
    expect(result).toEqual({ a: 1, b: 3, c: 4 });
  });

  it("returns a new object and does not mutate the target", () => {
    const target = { a: 1 };
    const source = { b: 2 };
    const result = deepMerge(target as Record<string, unknown>, source);
    expect(result).not.toBe(target);
    expect(target).toEqual({ a: 1 });
    expect(result).toEqual({ a: 1, b: 2 });
  });

  it("merges nested objects recursively instead of replacing", () => {
    const target = { nested: { a: 1, b: 2 }, keep: true };
    const source = { nested: { b: 3, c: 4 } };
    const result = deepMerge(target as Record<string, unknown>, source);
    expect(result).toEqual({ nested: { a: 1, b: 3, c: 4 }, keep: true });
  });

  it("does not mutate nested target objects", () => {
    const target = { nested: { a: 1 } };
    const source = { nested: { b: 2 } };
    const result = deepMerge(target as Record<string, unknown>, source);
    expect(target.nested).toEqual({ a: 1 });
    expect((result as any).nested).not.toBe(target.nested);
  });

  it("merges deeply nested objects at multiple levels", () => {
    const target = { l1: { l2: { l3: { a: 1, keep: "x" } } } };
    const source = { l1: { l2: { l3: { b: 2 } } } };
    const result = deepMerge(target as Record<string, unknown>, source);
    expect(result).toEqual({ l1: { l2: { l3: { a: 1, keep: "x", b: 2 } } } });
  });

  it("replaces arrays entirely rather than merging them", () => {
    const target = { arr: [1, 2, 3] };
    const source = { arr: [9] };
    const result = deepMerge(target as Record<string, unknown>, source);
    expect((result as any).arr).toEqual([9]);
  });

  it("clones the source array instead of sharing the reference", () => {
    const source = { arr: [1, 2] };
    const result = deepMerge({} as Record<string, unknown>, source);
    expect((result as any).arr).toEqual([1, 2]);
    expect((result as any).arr).not.toBe(source.arr);
  });

  it("replaces a target object with a source array", () => {
    const target = { val: { a: 1 } };
    const source = { val: [1, 2] };
    const result = deepMerge(target as Record<string, unknown>, source);
    expect((result as any).val).toEqual([1, 2]);
  });

  it("clones Date objects instead of sharing the reference", () => {
    const date = new Date("2020-01-01T00:00:00Z");
    const source = { when: date };
    const result = deepMerge({} as Record<string, unknown>, source);
    expect((result as any).when).toBeInstanceOf(Date);
    expect((result as any).when).not.toBe(date);
    expect((result as any).when.getTime()).toBe(date.getTime());
  });

  it("overwrites a target Date with a cloned source Date", () => {
    const target = { when: new Date("2000-01-01T00:00:00Z") };
    const newDate = new Date("2021-06-15T12:00:00Z");
    const result = deepMerge(target as Record<string, unknown>, { when: newDate });
    expect((result as any).when.getTime()).toBe(newDate.getTime());
    expect((result as any).when).not.toBe(newDate);
  });

  it("supports symbol keys from the source", () => {
    const sym = Symbol("s");
    const target = { a: 1 };
    const source: Record<string | symbol, unknown> = { [sym]: "value" };
    const result = deepMerge(target as Record<string | symbol, unknown>, source);
    expect((result as any)[sym]).toBe("value");
    expect((result as any).a).toBe(1);
  });

  it("preserves existing symbol keys on the target", () => {
    const sym = Symbol("keep");
    const target: Record<string | symbol, unknown> = { [sym]: "orig" };
    const result = deepMerge(target, { a: 1 } as any);
    expect((result as any)[sym]).toBe("orig");
  });

  it("rejects __proto__ keys to prevent prototype pollution", () => {
    const malicious = JSON.parse('{"__proto__": {"polluted": true}}');
    const result = deepMerge({} as Record<string, unknown>, malicious);
    expect(({} as any).polluted).toBeUndefined();
    expect((result as any).polluted).toBeUndefined();
    expect(Object.prototype.hasOwnProperty.call(result, "__proto__")).toBe(false);
  });

  it("skips the constructor key", () => {
    const source = JSON.parse('{"constructor": {"bad": true}, "safe": 1}');
    const result = deepMerge({} as Record<string, unknown>, source);
    expect((result as any).safe).toBe(1);
    expect(Object.prototype.hasOwnProperty.call(result, "constructor")).toBe(false);
  });

  it("skips the prototype key", () => {
    const source = JSON.parse('{"prototype": {"bad": true}, "safe": 2}');
    const result = deepMerge({} as Record<string, unknown>, source);
    expect((result as any).safe).toBe(2);
    expect(Object.prototype.hasOwnProperty.call(result, "prototype")).toBe(false);
  });

  it("replaces a target value with null when source is null", () => {
    const target = { a: { nested: 1 } };
    const source = { a: null };
    const result = deepMerge(target as Record<string, unknown>, source as any);
    expect((result as any).a).toBeNull();
  });

  it("adds a null value for a new key", () => {
    const result = deepMerge({} as Record<string, unknown>, { a: null } as any);
    expect(Object.prototype.hasOwnProperty.call(result, "a")).toBe(true);
    expect((result as any).a).toBeNull();
  });

  it("skips undefined values and preserves the target value", () => {
    const target = { a: 1 };
    const source = { a: undefined };
    const result = deepMerge(target as Record<string, unknown>, source as any);
    expect((result as any).a).toBe(1);
  });

  it("does not add a key when the source value is undefined", () => {
    const result = deepMerge({} as Record<string, unknown>, { b: undefined } as any);
    expect(Object.prototype.hasOwnProperty.call(result, "b")).toBe(false);
  });

  it("replaces a plain-object target with a primitive source value", () => {
    const target = { a: { nested: 1 } };
    const source = { a: 42 };
    const result = deepMerge(target as Record<string, unknown>, source as any);
    expect((result as any).a).toBe(42);
  });

  it("replaces a primitive target with a plain-object source value", () => {
    const target = { a: 1 };
    const source = { a: { nested: 2 } };
    const result = deepMerge(target as Record<string, unknown>, source as any);
    expect((result as any).a).toEqual({ nested: 2 });
  });

  it("assigns a source object when the target key is absent", () => {
    const result = deepMerge({} as Record<string, unknown>, { a: { x: 1 } } as any);
    expect((result as any).a).toEqual({ x: 1 });
  });

  it("overwrites primitive values of differing types", () => {
    const target = { a: 1, b: "str", c: true };
    const source = { a: "now-string", b: 0, c: false };
    const result = deepMerge(target as Record<string, unknown>, source as any);
    expect(result).toEqual({ a: "now-string", b: 0, c: false });
  });

  it("handles an empty source object", () => {
    const target = { a: 1, b: 2 };
    const result = deepMerge(target as Record<string, unknown>, {});
    expect(result).toEqual({ a: 1, b: 2 });
    expect(result).not.toBe(target);
  });

  it("handles an empty target object", () => {
    const result = deepMerge({} as Record<string, unknown>, { a: 1, b: 2 } as any);
    expect(result).toEqual({ a: 1, b: 2 });
  });

  it("treats class instances as non-plain objects and replaces them", () => {
    class Point {
      constructor(public x: number) {}
    }
    const target = { p: { x: 1 } };
    const inst = new Point(5);
    const result = deepMerge(target as Record<string, unknown>, { p: inst } as any);
    expect((result as any).p).toBe(inst);
  });

  it("replaces a plain object target with a class instance source", () => {
    class Box {
      value = 10;
    }
    const box = new Box();
    const result = deepMerge({ b: { value: 1 } } as Record<string, unknown>, { b: box } as any);
    expect((result as any).b).toBe(box);
    expect((result as any).b).toBeInstanceOf(Box);
  });

  it("merges objects created with Object.create(null)", () => {
    const nullProto = Object.create(null);
    nullProto.a = 1;
    const target = { data: nullProto };
    const source = { data: { b: 2 } };
    const result = deepMerge(target as Record<string, unknown>, source as any);
    expect((result as any).data.a).toBe(1);
    expect((result as any).data.b).toBe(2);
  });

  it("combines string and symbol keys in a single merge", () => {
    const sym = Symbol("id");
    const target: Record<string | symbol, unknown> = { name: "old" };
    const source: Record<string | symbol, unknown> = { name: "new", [sym]: 99 };
    const result = deepMerge(target, source);
    expect((result as any).name).toBe("new");
    expect((result as any)[sym]).toBe(99);
  });

  it("clones source Date over a target Date rather than deep-merging", () => {
    const target = { d: new Date(1000) };
    const src = new Date(2000);
    const result = deepMerge(target as Record<string, unknown>, { d: src } as any);
    expect((result as any).d.getTime()).toBe(2000);
    expect((result as any).d).not.toBe(src);
  });

  it("handles zero and false as valid non-skipped values", () => {
    const target = { a: 1, b: true };
    const result = deepMerge(target as Record<string, unknown>, { a: 0, b: false } as any);
    expect((result as any).a).toBe(0);
    expect((result as any).b).toBe(false);
  });
});
